-
-	icons := map[string]string{
-		"done":        "✓",
-		"in_progress": "⧖",
-		"ready":       "○",
-		"blocked":     "◌",
-	}
-
-	colors := map[string]lipgloss.Style{
-		"done":        Success,
-		"in_progress": Warning,
-		"ready":       Info,
-		"blocked":     Dim,
